  } catch (error) {
    errorHandler(res, error);
  }
});

router.get('/', async (req, res) => {
  try {
    const members = await service.getAllMembers(req.params.projectId);
    res.json({ members: Object.values(members) });
  } catch (error) {
    errorHandler(res, error);
  }
});

module.exports = router;
